	Date    = "unknown"
)

// Banner for DDx
const banner = `
██████  ██████  ██   ██
██   ██ ██   ██  ██ ██
██   ██ ██   ██   ███
██   ██ ██   ██  ██ ██
██████  ██████  ██   ██

